UPDATE ctgb_products SET gebruiksvoorschriften = '[{"gewas": "Sierbeplanting (planten in de vollegrond), Kamerplanten", "locatie": "Binnen", "toepassingsmethode": "Poederen, Voor uitplanten", "maxToepassingen": 1, "opmerkingen": ["Toepassingsgebied: Sierplanten en Kamerplanten (Opkweek plantmateriaal)  \n\nDosering middel per toepassing: de stekken met de\nonderste 1-2 cm in het poeder dippen.\n\nDe dosering (hoeveelheid middel per stek) wordt bepaald door dikte en structuur van de stek. De ondereindjes van de onbewortelde stekken worden in water bevochtigd, waarna de stekken met de onderste 1-2 cm in het poeder worden gedoopt. Het overtollige poeder wordt verwijderd door voorzichtig afkloppen, waarna de stekken geplant worden."], "wCodes": ["W1"]}]'::jsonb, last_synced_at = NOW() WHERE toelatingsnummer = '12078';
